// Пример базового if
const age = 18;
if (age >= 18) {
  console.log('Вы взрослый!');
}
// Вывод: Вы взрослый!

// Пример if и else
const temperature = 15;
if (temperature > 20) {
  console.log('Тепло.');
} else {
  console.log('Прохладно.');
}
// Вывод: Прохладно.

// Пример else if
const score = 85;
if (score >= 90) {
  console.log('Оценка: A');
} else if (score >= 80) {
  console.log('Оценка: B');
} else if (score >= 70) {
  console.log('Оценка: C');
} else {
  console.log('Оценка: D или ниже');
}
// Вывод: Оценка: B

// Пример else
const day = 'Понедельник';
if (day === 'Суббота') {
  console.log('Сегодня выходной!');
} else if (day === 'Воскресенье') {
  console.log('Сегодня выходной!');
} else {
  console.log('Сегодня рабочий день.');
}
// Вывод: Сегодня рабочий день.

// Пример вложенного if
const age = 16;
const hasPermission = true;
if (age >= 18) {
  console.log('Вы взрослый.');
} else {
  if (hasPermission) {
    console.log('Вы можете войти с разрешением.');
  } else {
    console.log('У вас нет разрешения на вход.');
  }
}
// Вывод: Вы можете войти с разрешением.

// Пример с ошибкой
// Ошибка: Неправильное условие
const temperature = 25;
if (temperature = 30) { // = вместо == или ===
  console.log('Тепло.');
} else {
  console.log('Прохладно.');
}
// Вывод: Тепло. (ошибка, потому что temperature устанавливается в 30)

// Правильный подход
if (temperature === 30) {
  console.log('Тепло.');
} else {
  console.log('Прохладно.');
}
// Вывод: Прохладно.

